433	  updateViewFilter: (planViewId: string, filterId: string, patch: Partial<ViewFilter>) => void;
434	  removeViewFilter: (planViewId: string, filterId: string) => void;
435	
436	  /**
437	   * VIE-04: client-only temporary visibility override scoped to one view.
438	   * `mode: 'isolate'` shows only the listed categories / element ids;
439	   * `mode: 'hide'` hides them. Cleared on view change or explicit reset;
440	   * never persisted.
441	   */
442	  temporaryVisibility: TemporaryVisibility | null;
443	  setTemporaryVisibility: (next: TemporaryVisibility | null) => void;
444	  clearTemporaryVisibility: () => void;
445	  /** SKB-23 — set/clear the per-phase preview filter. */
446	  setViewerPhaseFilter: (next: { phases: string[]; includeUntagged: boolean } | null) => void;
447	  clearViewerPhaseFilter: () => void;
448	
449	  setActivity: (e: ActivityEvent[]) => void;
450	  setIdentity: (userId: string, display: string, peerId: string) => void;
451	};
452	
453	export type TemporaryVisibilityMode = 'isolate' | 'hide';
454	
455	export type TemporaryVisibility = {
456	  /** plan_view, viewpoint, or other view scope this override is bound to. */
457	  viewId: string;
458	  mode: TemporaryVisibilityMode;
459	  /** Element kinds (`wall`, `door`, …) covered by the override. */
460	  categories: string[];
461	  /** Specific element ids covered by the override. */
462	  elementIds?: string[];
463	};
464	
465	/**
466	 * VIE-04: returns true when an element of `kind` should be drawn under the
467	 * given temporary-visibility override. Pass `null` when there's no override
468	 * active — the helper short-circuits to "visible".
469	 */
470	export function isElementVisibleUnderTemporaryVisibility(
471	  kind: string,
472	  override: TemporaryVisibility | null,
473	  elementId?: string,
474	): boolean {
475	  if (override === null) return true;
476	  const inCategorySet = override.categories.includes(kind);
477	  const inElementSet = elementId ? (override.elementIds ?? []).includes(elementId) : false;
478	  const inSet = inCategorySet || inElementSet;
479	  return override.mode === 'isolate' ? inSet : !inSet;
480	}
