  | 'mirror'
  | 'copy'
  | 'component'
  | 'move'
  | 'rotate'
  | 'scale'
  | 'array'
  | 'place-group'
  | 'section'
  | 'mass-box'
  | 'mass-extrusion'
  | 'mass-revolution'
  | 'text'
  | 'leader-text'
  | 'angular-dimension'
  | 'radial-dimension'
  | 'diameter-dimension'
  | 'arc-length-dimension'
  | 'spot-elevation'
  | 'spot-coordinate'
  | 'slope-annotation'
