  | 'north-arrow'
  | 'brace'
  | 'ramp'
  | 'column-at-grids'
  | 'beam-system'
  | 'interior-elevation'
  | 'walkthrough'
  | 'roof-by-extrusion'
  | 'revision-cloud'
