  | 'excavation';

export type PresencePeers = Record<
  string,
  {
    peerId?: string;
    userId?: string;
    name?: string;
    color?: string;
    cursorMm?: { xMm: number; yMm: number };
    selectionId?: string;
    viewer?: string;
  }
>;

export type UxComment = {
  id: string;
  userDisplay: string;
  body: string;
  elementId?: string | null;
  levelId?: string | null;
  anchorXMm?: number | null;
  anchorYMm?: number | null;
  resolved: boolean;
  createdAt?: string;
};

export type ActivityEvent = {
  id: number;
  userId: string;
  revisionAfter: number;
  createdAt: string;
  commandTypes: string[];
};

export type CategoryOverride = {
  dxf?: {
    hiddenLayerNames?: string[];
  };
  projection?: {
    lineWeightFactor?: number;
    lineColor?: string | null;
    linePattern?: string | null;
    fillColor?: string | null;
    halftone?: boolean;
    transparency?: number;
  };
  cut?: {
    lineWeightFactor?: number;
    lineColor?: string | null;
    linePattern?: string | null;
    fillColor?: string | null;
    halftone?: boolean;
    transparency?: number;
  };
