};

export type CategoryOverrides = Record<string, CategoryOverride>;

export type FilterRule = {
  field: string;
  operator: 'equals' | 'not-equals' | 'contains' | 'not-contains';
  value: string;
};

export type ViewFilter = {
  id: string;
  name: string;
  rules: FilterRule[];
