export type ViewerCameraActionKind = 'fit' | 'reset' | 'fit-context';
export type OsmLayerName = 'buildings' | 'roads' | 'trees' | 'water' | 'green';
export type ViewerRenderStyle =
  | 'shaded'
  | 'wireframe'
