10	type ModelRuntimeHelpers = {
11	  coerceElement: (id: string, raw: Record<string, unknown>) => Element | null;
12	  coerceViolation: (value: unknown) => Violation;
13	  defaultLevelId: (elements: Record<string, Element>) => string | undefined;
14	};
