16	export type ModelRuntimeSlice = Pick<
17	  StoreState,
18	  | 'revision'
19	  | 'elementsById'
20	  | 'violations'
21	  | 'selectedIds'
22	  | 'planProjectionPrimitives'
23	  | 'planRoomSchemeWireReadout'
24	  | 'scheduleBudgetHydration'
25	  | 'lastLevelElevationPropagationEvidence'
26	  | 'linkSourceRevisions'
27	  | 'hydrateFromSnapshot'
28	  | 'applyDelta'
29	  | 'select'
30	  | 'toggleSelectedId'
31	  | 'clearSelectedIds'
32	  | 'mergeElements'
33	  | 'importFamilyDefinitions'
34	>;
35	
36	export function createModelRuntimeSlice(
37	  set: StoreSet,
38	  get: StoreGet,
39	  helpers: ModelRuntimeHelpers,
40	): ModelRuntimeSlice {
41	  const { coerceElement, coerceViolation, defaultLevelId } = helpers;
42	
43	  return {
44	    revision: 0,
45	    elementsById: {},
46	    violations: [],
47	    selectedIds: [],
48	    planProjectionPrimitives: null,
49	    planRoomSchemeWireReadout: null,
50	    scheduleBudgetHydration: null,
51	    lastLevelElevationPropagationEvidence: null,
52	    linkSourceRevisions: {},
53	
54	    hydrateFromSnapshot: (snap: Snapshot) => {
55	      const elements: Record<string, Element> = {};
56	
57	      for (const [id, raw] of Object.entries(snap.elements ?? {})) {
58	        const typed = coerceElement(id, raw as Record<string, unknown>);
59	        if (typed) elements[id] = typed;
60	      }
61	
62	      const curLevel = get().activeLevelId;
63	      const prevPv = get().activePlanViewId;
64	      const prevVp = get().activeViewpointId;
65	
66	      set({
67	        modelId: snap.modelId,
68	        revision: snap.revision,
69	        elementsById: elements,
70	        violations: (snap.violations ?? []).map(coerceViolation),
71	        activeLevelId:
72	          curLevel && elements[curLevel]?.kind === 'level' ? curLevel : defaultLevelId(elements),
73	        planProjectionPrimitives: null,
74	        planRoomSchemeWireReadout: null,
75	        scheduleBudgetHydration: null,
76	        lastLevelElevationPropagationEvidence: null,
77	        linkSourceRevisions:
78	          snap.linkSourceRevisions && typeof snap.linkSourceRevisions === 'object'
79	            ? { ...snap.linkSourceRevisions }
80	            : {},
81	        activePlanViewId: prevPv && elements[prevPv]?.kind === 'plan_view' ? prevPv : undefined,
82	        activeViewpointId: prevVp && elements[prevVp]?.kind === 'viewpoint' ? prevVp : undefined,
83	      });
84	    },
85	
86	    applyDelta: (d: ModelDelta) => {
87	      const merged = { ...get().elementsById };
88	
89	      const dels = Array.isArray((d as { removedIds?: unknown }).removedIds)
90	        ? (d.removedIds as string[])
91	        : Array.isArray((d as { removed_ids?: unknown }).removed_ids)
92	          ? (d as unknown as { removed_ids: string[] }).removed_ids
93	          : [];
94	
95	      for (const rid of dels) {
96	        delete merged[rid];
97	      }
98	
99	      for (const [eid, raw] of Object.entries(d.elements ?? {})) {
100	        const typed = coerceElement(eid, raw as Record<string, unknown>);
101	        if (typed) merged[eid] = typed;
102	      }
103	
104	      const st = get();
105	      const pv = st.activePlanViewId;
106	      const vp = st.activeViewpointId;
107	
108	      set({
109	        revision: d.revision,
110	        elementsById: merged,
111	        violations: (d.violations ?? []).map(coerceViolation),
112	        planProjectionPrimitives: null,
113	        planRoomSchemeWireReadout: null,
114	        scheduleBudgetHydration: null,
115	        lastLevelElevationPropagationEvidence: null,
116	        activePlanViewId: pv && merged[pv]?.kind === 'plan_view' ? pv : undefined,
117	        activeViewpointId: vp && merged[vp]?.kind === 'viewpoint' ? vp : undefined,
118	      });
119	    },
120	
121	    select: (id) => set({ selectedId: id, selectedIds: [] }),
122	
123	    toggleSelectedId: (id) =>
124	      set((state) => {
125	        if (state.selectedId === id) {
126	          const [nextPrimary, ...rest] = state.selectedIds;
127	          return { selectedId: nextPrimary, selectedIds: rest };
128	        }
129	        if (state.selectedIds.includes(id)) {
130	          return { selectedIds: state.selectedIds.filter((x) => x !== id) };
131	        }
132	        if (!state.selectedId) {
133	          return { selectedId: id, selectedIds: [] };
134	        }
135	        return { selectedIds: [...state.selectedIds, id] };
136	      }),
137	
138	    clearSelectedIds: () => set({ selectedIds: [] }),
139	
140	    mergeElements: (elements) =>
141	      set((state) => {
142	        const next = { ...state.elementsById };
143	        for (const el of elements) {
144	          if (el && typeof (el as { id?: unknown }).id === 'string') {
145	            next[(el as { id: string }).id] = el as Element;
146	          }
147	        }
148	        return { elementsById: next };
149	      }),
150	
151	    importFamilyDefinitions: (defs) =>
152	      set((state) => {
153	        const next = { ...(state.userFamilies ?? {}) };
154	        for (const def of defs) next[def.id] = def;
155	        return { userFamilies: next };
156	      }),
157	  };
158	}

